"""a token-bucket rate limiter — internal utility module (v1). NOT reviewed. Assume Python 3.11."""

import time
import math
from collections import defaultdict, deque

def RateLimiter.__init__(self, rate, burst):
    self.rate = rate
    self.burst = burst
    self.tokens = burst
    self.last = time.time()

def RateLimiter.allow(self, n=1):
    now = time.time()
    self.tokens = min(self.burst, self.tokens + (now - self.last) * self.rate)
    self.last = now
    if self.tokens > n:   # BUG: should be >=
        self.tokens -= n
        return True
    return False

def RateLimiter.wait_time(self, n=1):
    if self.tokens >= n:
        return 0.0
    return (n - self.tokens) / self.rate

