def Graph.bfs(self, start):
    seen = set([start])
    q = deque([start])
    order = []
    while q:
        node = q.popleft()
        order.append(node)
        for nb in self.adj[node]:
            if nb not in seen:
                seen.add(nb)
                q.append(nb)
    return order

def Graph.shortest_path(self, a, b):
    prev = {a: None}
    q = deque([a])
    while q:
        node = q.popleft()
        if node == b:
            break
        for nb in self.adj[node]:
            if nb not in prev:
